import React, { useState } from 'react';
import axios from 'axios';
import { Save, Trash2, Loader2, FileSpreadsheet, Send } from 'lucide-react';

const GestionInventario = ({ localId, onComplete }) => {
    // Definimos las columnas para que sea fácil de mantener
    const campos = ['tipo', 'marca', 'contenido', 'categoria', 'precioNuevo', 'precioViejo', 'stock', 'fechaInicio', 'fechaFin'];

    const crearFilasVacias = (cant) => Array(cant).fill().map(() => ({
        tipo: '', marca: '', contenido: '', categoria: 'Almacén', 
        precioNuevo: '', precioViejo: '', stock: '', 
        fechaInicio: '', fechaFin: ''
    }));

    const [filas, setFilas] = useState(crearFilasVacias(10));
    const [loading, setLoading] = useState(false);

    const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

    const handlePaste = (e, filaIndex, colIndex) => {
        const pasteData = e.clipboardData.getData('text');
        if (!pasteData) return;

        const rows = pasteData.split(/\r\n|\n|\r/);
        const nuevasFilas = [...filas];

        rows.forEach((rowText, i) => {
            const trimmedRow = rowText.trim();
            if (!trimmedRow) return;

            const targetFilaIndex = filaIndex + i;
            if (!nuevasFilas[targetFilaIndex]) {
                nuevasFilas[targetFilaIndex] = crearFilasVacias(1)[0];
            }

            const cells = rowText.split('\t');
            cells.forEach((cellText, j) => {
                const targetColIndex = colIndex + j;
                const fieldName = campos[targetColIndex];
                if (fieldName) {
                    nuevasFilas[targetFilaIndex][fieldName] = cellText.trim();
                }
            });
        });

        setFilas(nuevasFilas);
        e.preventDefault();
    };

    const handleInputChange = (index, field, value) => {
        const nuevas = [...filas];
        nuevas[index][field] = value;
        setFilas(nuevas);
    };

    const procesarEnvio = async (publicarInmediatamente = false) => {
        const validos = filas.filter(f => f.tipo && f.marca && f.precioNuevo);
        
        if (validos.length === 0) {
            return alert("Completa al menos Tipo, Marca y Precio.");
        }

        // Si se va a publicar, validar que tengan fechas
        if (publicarInmediatamente) {
            const faltanFechas = validos.some(f => !f.fechaInicio || !f.fechaFin);
            if (faltanFechas) {
                return alert("Para publicar directamente, todas las filas deben tener fecha de inicio y fin.");
            }
        }

        setLoading(true);
        try {
            await axios.post(`${API_URL}/api/ofertas/bulk`, {
                localId,
                publicar: publicarInmediatamente,
                productos: validos.map(p => ({
                    ...p,
                    producto: `${p.tipo} ${p.marca} ${p.contenido}`.trim(),
                    precioNuevo: Number(p.precioNuevo),
                    precioViejo: Number(p.precioViejo) || Number(p.precioNuevo),
                    stock: Number(p.stock) || 0,
                    fechaInicioOferta: p.fechaInicio,
                    fechaFinOferta: p.fechaFin
                }))
            });

            alert(publicarInmediatamente ? "¡Productos publicados con éxito!" : "¡Borradores guardados!");
            setFilas(crearFilasVacias(10));
            onComplete();
        } catch (err) {
            alert("Error: " + (err.response?.data?.error || err.message));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={container}>
            <div style={header}>
                <FileSpreadsheet size={20} color="#107c41" />
                <h3 style={{margin:0}}>Carga Masiva Profesional</h3>
                <span style={tip}>Excel: Tipo | Marca | Contenido | Cat | $ Nuevo | $ Viejo | Stock | Inicio | Fin</span>
            </div>

            <div style={tableWrapper}>
                <table style={table}>
                    <thead>
                        <tr style={thr}>
                            <th style={th}>Tipo</th>
                            <th style={th}>Marca</th>
                            <th style={th}>Contenido</th>
                            <th style={th}>Categoría</th>
                            <th style={th}>$ Oferta</th>
                            <th style={th}>$ Normal</th>
                            <th style={th}>Stock</th>
                            <th style={{...th, background: '#fff7ed'}}>Inicio Promo</th>
                            <th style={{...th, background: '#fff7ed'}}>Fin Promo</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filas.map((f, i) => (
                            <tr key={i}>
                                {campos.map((field, j) => (
                                    <td key={j} style={td}>
                                        <input
                                            type={field.startsWith('fecha') ? 'date' : 'text'}
                                            style={input}
                                            value={f[field]}
                                            onChange={(e) => handleInputChange(i, field, e.target.value)}
                                            onPaste={(e) => handlePaste(e, i, j)}
                                            placeholder="..."
                                        />
                                    </td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <div style={footer}>
                <button onClick={() => setFilas(crearFilasVacias(10))} style={btnSec}>Limpiar Grilla</button>
                <div style={{display: 'flex', gap: '10px'}}>
                    <button onClick={() => procesarEnvio(false)} style={btnSave} disabled={loading}>
                        <Save size={18}/> Guardar Borrador
                    </button>
                    <button onClick={() => procesarEnvio(true)} style={btnPub} disabled={loading}>
                        {loading ? <Loader2 className="animate-spin" size={18}/> : <Send size={18}/>}
                        PUBLICAR AHORA
                    </button>
                </div>
            </div>
        </div>
    );
};

// --- ESTILOS ---
const container = { background: '#fff', borderRadius: '12px', border: '1px solid #ddd', marginBottom: '30px', overflow: 'hidden', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' };
const header = { padding: '15px', background: '#f8fafc', borderBottom: '1px solid #ddd', display: 'flex', alignItems: 'center', gap: '10px' };
const tip = { fontSize: '0.7rem', color: '#64748b', marginLeft: 'auto', fontWeight: '500' };
const tableWrapper = { overflowX: 'auto', maxHeight: '450px' };
const table = { width: '100%', borderCollapse: 'collapse' };
const thr = { background: '#f1f5f9' };
const th = { padding: '12px 10px', border: '1px solid #ddd', fontSize: '0.75rem', textAlign: 'left', color: '#475569', fontWeight: 'bold', whiteSpace: 'nowrap' };
const td = { border: '1px solid #ddd', padding: 0 };
const input = { width: '100%', padding: '10px', border: 'none', outline: 'none', fontSize: '0.85rem', background: 'transparent' };
const footer = { padding: '20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc', borderTop: '1px solid #ddd' };
const btnPriBase = { border: 'none', padding: '12px 25px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px', transition: 'all 0.2s' };
const btnSave = { ...btnPriBase, background: '#64748b', color: '#fff' };
const btnPub = { ...btnPriBase, background: '#10b981', color: '#fff', fontSize: '1rem', boxShadow: '0 4px 6px rgba(16, 185, 129, 0.2)' };
const btnSec = { background: '#fff', border: '1px solid #ddd', padding: '10px 15px', borderRadius: '8px', cursor: 'pointer', color: '#64748b' };

export default GestionInventario;
